resource "kubernetes_deployment" "backend" {
  #checkov:skip=CKV_K8S_14:Image tag is fixed (not latest) in variable default and tfvars; Checkov cannot statically resolve Terraform variable-sourced image refs in the Kubernetes provider.
  #checkov:skip=CKV_K8S_43:comic-backend is a local Minikube build with no stable remote registry digest. In CI/CD the image is pushed to a registry and digest pinned via -var=backend_image at plan time.
  metadata {
    name      = "backend"
    namespace = kubernetes_namespace.env.metadata[0].name

    labels = {
      app = "backend"
    }
  }

  spec {
    replicas = var.backend_replicas

    selector {
      match_labels = {
        app = "backend"
      }
    }

    template {
      metadata {
        labels = {
          app = "backend"
        }

        annotations = {
          "vault.hashicorp.com/agent-inject"                 = "true"
          "vault.hashicorp.com/role"                         = "comic-backend-${var.environment}"
          "vault.hashicorp.com/agent-inject-secret-config"   = "secret/data/comic-book-library/${var.environment}"
          "vault.hashicorp.com/agent-inject-template-config" = <<EOT
{{- with secret "secret/data/comic-book-library/${var.environment}" -}}
export DB_NAME="{{ .Data.data.MYSQL_DATABASE }}"
export DB_USER="{{ .Data.data.MYSQL_USER }}"
export DB_PASSWORD="{{ .Data.data.MYSQL_PASSWORD }}"
export JWT_SECRET="{{ .Data.data.JWT_SECRET }}"
export SECRET_KEY="{{ .Data.data.SECRET_KEY }}"
{{- end }}
EOT
        }
      }

      spec {
        service_account_name = kubernetes_service_account.backend.metadata[0].name

        security_context {
          run_as_non_root = true
          run_as_user     = 1000
          run_as_group    = 1000
          fs_group        = 1000
          seccomp_profile {
            type = "RuntimeDefault"
          }
        }

        container {
          name              = "backend"
          image             = var.backend_image
          image_pull_policy = var.image_pull_policy

          port {
            container_port = var.backend_port
          }

          command = ["/bin/sh", "-c"]

          args = ["tr -d '\\r' < /vault/secrets/config > /tmp/vault-env && . /tmp/vault-env && exec ./entrypoint.sh python run.py"]

          env {
            name  = "APP_ENV"
            value = var.environment
          }

          env {
            name  = "FLASK_ENV"
            value = var.flask_env
          }

          env {
            name  = "DB_HOST"
            value = kubernetes_service.mysql.metadata[0].name
          }

          env {
            name  = "DB_PORT"
            value = tostring(var.mysql_port)
          }

          resources {
            requests = {
              cpu    = "100m"
              memory = "256Mi"
            }
            limits = {
              cpu    = "500m"
              memory = "512Mi"
            }
          }

          liveness_probe {
            http_get {
              path = "/health"
              port = var.backend_port
            }
            initial_delay_seconds = 15
            period_seconds        = 20
            timeout_seconds       = 5
            failure_threshold     = 3
          }

          readiness_probe {
            http_get {
              path = "/health"
              port = var.backend_port
            }
            initial_delay_seconds = 10
            period_seconds        = 10
            timeout_seconds       = 3
            failure_threshold     = 3
          }

          security_context {
            allow_privilege_escalation = false
            read_only_root_filesystem  = true
            run_as_non_root            = true
            run_as_user                = 1000
            capabilities {
              drop = ["ALL", "NET_RAW"]
            }
          }

