          #   /var/run/apache2  â€” apache2.pid and unix socket
          #   /var/lock/apache2 â€” accept.lock written by mpm module
          #   /var/lib/apache2  â€” module state (mpm-event scoreboard, etc.)
          #   /tmp              â€” general temp; upload buffer
          #   /var/lib/php/sessions â€” PHP session storage (default save_path in php:apache)
          #   /var/www/html/tmp â€” phpMyAdmin export/import temp directory
          # Apache logs are symlinked to /dev/stdout and /dev/stderr in the base image,
          # so /var/log/apache2 does not need a writable mount.
          volume_mount {
            name       = "apache-run"
            mount_path = "/var/run/apache2"
          }
          volume_mount {
            name       = "apache-lock"
            mount_path = "/var/lock/apache2"
          }
          volume_mount {
            name       = "apache-lib"
            mount_path = "/var/lib/apache2"
          }
          volume_mount {
            name       = "tmp"
            mount_path = "/tmp"
          }
          volume_mount {
            name       = "php-sessions"
            mount_path = "/var/lib/php/sessions"
          }
          volume_mount {
            name       = "pma-tmp"
            mount_path = "/var/www/html/tmp"
          }
        }

        volume {
          name = "apache-run"
          empty_dir {}
        }
        volume {
          name = "apache-lock"
          empty_dir {}
        }
        volume {
          name = "apache-lib"
          empty_dir {}
        }
        volume {
          name = "tmp"
          empty_dir {}
        }
        volume {
          name = "php-sessions"
          empty_dir {}
        }
        volume {
          name = "pma-tmp"
          empty_dir {}
        }
      }
    }
  }
}

